<span class="line">        <span class="token punctuation">.</span><span class="token function">set</span><span class="token punctuation">(</span><span class="token string">&quot;email&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;new@test.com&quot;</span><span class="token punctuation">)</span></span>
